import{_ as s,o,c as n,a6 as a,es as t,ff as p,fg as g,fh as i,fi as e,fj as l,fk as d,fl as m,fm as c,fn as h,fo as _,fp as f,fq as u,fr as b,fs as k,ft as D,fu as x,fv as P,fw as K,fx as A,fy as R,fz as T,fA as I,fB as C,fC as H,fD as S,fE as E,fF as L,fG as F,fH as $}from"./chunks/framework.UYVGz2W_.js";const v=JSON.parse('{"title":"Kitsuの使い方","description":"","frontmatter":{},"headers":[],"relativePath":"ja/configure-kitsu/index.md","filePath":"ja/configure-kitsu/index.md"}'),B={name:"ja/configure-kitsu/index.md"};function G(N,r,W,y,j,O){return o(),n("div",null,[...r[0]||(r[0]=[a('<h1 id="kitsuの使い方" tabindex="-1">Kitsuの使い方 <a class="header-anchor" href="#kitsuの使い方" aria-label="Permalink to “Kitsuの使い方”">​</a></h1><p>Kitsuを使用すると、ユーザーは2Dおよび3D制作、VFX、ビデオゲーム、その他の関連作業を含む、さまざまな制作プロジェクトを追跡することができます。</p><p>Kitsuで追跡できるコンテンツは、静止画広告のようなシンプルなものから、3時間の長編映画まで、さまざまな要素のプロジェクトに対応できます。</p><p>しかし、制作に取り掛かる前に、まず<strong>スタジオワークフロー</strong>を設定する必要があります。</p><h2 id="スタジオワークフロー" tabindex="-1">スタジオワークフロー <a class="header-anchor" href="#スタジオワークフロー" aria-label="Permalink to “スタジオワークフロー”">​</a></h2><h3 id="スタジオワークフローの理解" tabindex="-1">スタジオワークフローの理解 <a class="header-anchor" href="#スタジオワークフローの理解" aria-label="Permalink to “スタジオワークフローの理解”">​</a></h3><p>::: 警告 定義 ワークフローとは、制作における作業プロセスを構成するタスクの構造化された連携を指します。 :::</p><p>例えば、CGI制作では、モデリング、リギング、シェーディングなどのタスクが実行され、アセットが完成します。</p><p>::: 警告 定義</p><ul><li>モデリング、シェーディングなどのプロセスは、<strong>タスクタイプ</strong>と呼ばれます。</li><li>アセットやショットなどの個々のオブジェクトは「<strong>エンティティ」</strong>と呼ばれます。</li><li>「<strong>タスク」</strong>とは、実行する必要のある特定のアクションやアクティビティを指します。 タスクはエンティティに帰属させることができ、通常はタスクタイプで分類されます。</li></ul><p>:::</p><p>対応するタスクを持つエンティティは、アセットワークフローの基礎となります。 その後、各タスクはアーティストに割り当てられます。アセットのワークフローを決定したら、ショットやシーケンスなどについても同様に決定します。</p><p>タスクのワークフローが定義されたら、次のステップでは<strong>承認ワークフロー</strong>を確立します。これには、チーム内でのコミュニケーションに使用するステータスをすべて定義することが含まれます。ステータスは、制作の進行状況を追跡するのにも役立ちます。</p><p>制作の<strong>ワークフロー</strong>は、タスクとステータスの合計です。</p><h3 id="グローバルライブラリと制作ライブラリ" tabindex="-1">グローバルライブラリと制作ライブラリ <a class="header-anchor" href="#グローバルライブラリと制作ライブラリ" aria-label="Permalink to “グローバルライブラリと制作ライブラリ”">​</a></h3><p>Kitsuには2種類の<strong>ライブラリ</strong>があります。</p><ul><li><p>1つ目はスタジオレベルの<strong>グローバルライブラリ</strong>です。 スタジオマネージャーのみがアクセスできます。</p></li><li><p>2つ目は<strong>制作ライブラリ</strong>で、グローバルライブラリで作成した要素を選択して追加します。</p></li></ul><p>各制作を特定のワークフローで分離しておくことが目的です。</p><p><strong>グローバルライブラリ</strong>では、部門、タスクタイプ、タスクステータス、アセットタイプ、ステータスの自動化を作成および変更することができます。必要な数だけ要素を作成し、任意の名前を付け、ニーズに合った最適な色やオプションを選択することができます。</p><p><strong>グローバルライブラリ</strong>に要素が追加されたら、<strong>グローバルライブラリ</strong>から新たに作成した要素を<strong>プロダクションライブラリ</strong>に追加することができます。</p><h2 id="部署" tabindex="-1">部署 <a class="header-anchor" href="#部署" aria-label="Permalink to “部署”">​</a></h2><h3 id="部署の作成" tabindex="-1">部署の作成 <a class="header-anchor" href="#部署の作成" aria-label="Permalink to “部署の作成”">​</a></h3><p>部署は、スーパーバイザーやアーティストが各自の作業に集中できるよう設計されています。 ユーザーが1つまたは複数の部署にリンクされると、スーパーバイザーやアーティストは、そのタスクタイプに関連するすべてのタスクのフィルタリングされたビューに直接アクセスできるようになります。 部署は、その部署内のユーザーに表示されるメタデータカラムを定義するためにも使用されます。</p><p>メタデータ列が部署に関連付けられている場合、その列は、その部署内のユーザーのみに表示されます。メタデータ列が部署に関連付けられていない場合、その列は、すべてのユーザーに表示されます。</p><p>::: ヒント デフォルトでは、Kitsuは、作業を開始する際に役立ついくつかのサンプル部署を提供しています。 :::</p><p>スタジオの部署を定義することは、通常、セットアップの最初のステップです。人やタスクの種類など、複数のオブジェクトが部署に関連付けられます。</p><p>メインメニューの <img src="'+t+'" alt="メインメニュー"> で、 <strong>管理</strong>セクションの<strong>部署</strong>ページを選択します。</p><p><img src="'+p+'" alt="タスクタイプ"></p><p>さらに多くの部門を作成する必要がある場合は、[部門作成] ボタンをクリックします。</p><p>部門を追加する際には、以下の項目を定義する必要があります。</p><ul><li>部門名</li><li>色（円形の小さな円として、列のタスクタイプまたはカスタム列の隣に表示されます）</li></ul><p><img src="'+g+'" alt="Create department"></p><p>変更を保存するには、<strong>Confirm</strong>をクリックします。</p><p>部門の作成が完了すると、ページは次のようになります。各部門には固有の名前と色が割り当てられています。</p><p><img src="'+i+'" alt="Customized department"></p><h2 id="タスクの種類" tabindex="-1">タスクの種類 <a class="header-anchor" href="#タスクの種類" aria-label="Permalink to “タスクの種類”">​</a></h2><h3 id="新しいタスクの種類を作成する" tabindex="-1">新しいタスクの種類を作成する <a class="header-anchor" href="#新しいタスクの種類を作成する" aria-label="Permalink to “新しいタスクの種類を作成する”">​</a></h3><p>次に、制作物の管理と追跡に必要なすべての<strong>タスクの種類</strong>を作成します。タスクの種類は、アセット、ショット、シーケンス、エピソード、編集など、複数のエンティティに関連付けることができます。</p><p>メインメニュー <img src="'+t+'" alt="メインメニュー"> から <strong>管理</strong>セクションの<strong>タスクの種類</strong>ページを選択します。</p><p><img src="'+e+'" alt="タスクタイプ"></p><p>::: ヒント デフォルトでは、KitsuはCGI制作で使用できるいくつかのサンプルタスクタイプを提供しています。制作に関連のないものは、名前を変更したり削除したりすることができます。 :::</p><p>これらの<strong>タスクタイプ</strong>は、すでに部門にリンクされていることに気づくでしょう。</p><p><img src="'+l+'" alt="タスクタイプ 空"></p><p><img src="'+d+'" alt="タスクタイプの追加"> ボタンをクリックして、新しい<strong>タスクタイプ</strong>を作成することができます。</p><p>次に、タスクタイプに関するいくつかの情報を入力する必要があります。</p><ul><li>タスクタイプの名称</li><li>チームメンバーがこのタスクタイプで作業時間を記録する必要があるかどうか</li><li>どのエンティティで使用するか</li><li>どの部署にリンクするか</li><li>色（これはメインのスプレッドシートページの背景色に反映されます）</li></ul><p><img src="'+m+'" alt="タスクの作成"></p><p>以前に作成した<strong>部署</strong>が、タスクタイプをリンクするオプションとして利用できることに気づくでしょう。特定のタスクタイプに部署を関連付けることで、チームの組織化に役立ちます。</p><p><img src="'+c+'" alt="タスク部署の作成"></p><p><strong>確認</strong>をクリックして変更を保存します。</p><p>::: 警告 新しく作成したタスクタイプはリストの一番下に表示されます :::</p><p>順序を調整するには、<strong>タスクタイプ</strong>をクリックして、リスト内の適切な位置までドラッグするだけです。</p><p><img src="'+h+'" alt="タスクトップリストの作成"></p><p>おめでとうございます。これで、お客様の<strong>グローバルライブラリ</strong>にタスクタイプが作成されました。</p><p>::: 警告 制作を作成したら、<strong>シーケンス</strong>、<strong>エピソード</strong>、<strong>編集</strong>の各タスクタイプを<strong>制作ライブラリ</strong>に追加する必要があります。 :::</p><p>::: ヒント 制作のどの段階でも、必要に応じてこのセクションに戻って追加の<strong>タスクタイプ</strong>を作成し、ワークフローに追加することができます。 :::</p><h2 id="アセットタイプ" tabindex="-1">アセットタイプ <a class="header-anchor" href="#アセットタイプ" aria-label="Permalink to “アセットタイプ”">​</a></h2><h3 id="アセットワークフローの定義" tabindex="-1">アセットワークフローの定義 <a class="header-anchor" href="#アセットワークフローの定義" aria-label="Permalink to “アセットワークフローの定義”">​</a></h3><p>グローバルワークフローを作成したら、<strong>アセットタイプ</strong>を定義することができます。</p><p>ショットがシーケンスによって整理されるのと同様に、アセットは<strong>アセットタイプ</strong>によって整理されます。フォルダを使用して、すべてのアセットをカテゴリー別に整理するようなものと考えてください。</p><p>メインメニューの <img src="'+t+'" alt="メインメニュー"> で、 <strong>管理</strong>セクションの<strong>アセットタイプ</strong>ページを選択します。</p><p><img src="'+_+'" alt="アセットタイプメニュー"></p><p>::: ヒント デフォルトでは、KitsuはCGI制作に使用できるいくつかのサンプルアセットタイプを提供しています。 :::</p><p><img src="'+f+'" alt="Asset type default"></p><p>新しい<strong>アセットタイプ</strong>を作成するには、<img src="'+u+'" alt="Add Asset Types">ボタンをクリックします。</p><p>次に、<strong>アセットタイプ</strong>に関するいくつかの情報を入力する必要があります。</p><ul><li>アセットタイプの名称</li><li>特定のアセットタイプ用のワークフロー</li></ul><p>異なるアセットタイプには、異なるワークフローが存在します。例えば、環境アセットは通常リギング作業を必要としないため、キャラクターと比較すると環境のタスクは少なくなります。</p><p><img src="'+b+'" alt="アセットタイプ名の追加"></p><p>アセットタイプを<strong>作成</strong>または<strong>編集</strong>する際には、特定の<strong>タスクタイプ</strong>を追加することができます。このアセットタイプに対して特定のワークフローを選択しない場合、制作アセットのワークフローが適用されます。</p><p>ただし、このアセットタイプに対して特定のタスクタイプを選択した場合は、それらのみが制作に適用されます。</p><p>変更を保存するには、<strong>Confirm（確認）</strong>をクリックします。</p><p>新しい<strong>アセットタイプ</strong>が<strong>グローバルライブラリ</strong>に作成されました。制作物の作成時に使用できるようになります。</p><p>::: ヒント 制作物の作成中にいつでもこのセクションに戻って、必要に応じて追加の<strong>アセットタイプ</strong>を作成し、ワークフローに追加することができます。 :::</p><h2 id="タスクステータス" tabindex="-1">タスクステータス <a class="header-anchor" href="#タスクステータス" aria-label="Permalink to “タスクステータス”">​</a></h2><h3 id="承認ワークフローの定義" tabindex="-1">承認ワークフローの定義 <a class="header-anchor" href="#承認ワークフローの定義" aria-label="Permalink to “承認ワークフローの定義”">​</a></h3><p>次に、<strong>承認ワークフロー</strong>で使用するステータスを作成します。</p><p>メインメニューの <img src="'+t+'" alt="メインメニュー"> で、 <strong>管理</strong>セクションの<strong>タスクステータス</strong>ページを選択します。</p><p><img src="'+k+'" alt="タスクステータスメニュー"></p><p>::: ヒント デフォルトで、Kitsuにはすでにいくつかのステータスの例が用意されています。 :::</p><p><img src="'+D+'" alt="タスクステータス デフォルト"></p><p>ステータスは、レビューと承認プロセスの一部として、タスクが通過しなければならない特定の段階や条件を表します。</p><p>たとえば、<strong>「準備完了」</strong> <img src="'+x+'" alt="準備完了ステータス">ステータスは、アーティストが作業を開始するために必要なものがすべて揃っていることを示し、このステータスに達するまではタスクを開始してはならないことを意味します。</p><p><strong>WIP</strong> <img src="'+P+'" alt="WIP ステータス">: <strong>作業中</strong>ステータスは、アーティストがチームに現在作業中であることを知らせるために使用します。このステータスでは、他の担当者に割り当てる必要がないことを示します。</p><p><strong>WFA</strong><img src="'+K+'" alt="WFA ステータス">: <strong>承認待ち</strong>ステータスは、アーティストが作業を完了し、レビュー待ちの状態であることを上司に通知するために使用します。また、同様のステータスを上司が使用して、ディレクターに作業がレビュー可能になったことを通知することもできます。</p><p>完了！<a href="../img/getting-started/done_icon.png">完了ステータス</a>: <strong>完了</strong>ステータスは、すべての作業が完了し承認されたことを示します。これは、現在のタスクが完了し、次のプロセス段階を開始できることを意味します。</p><p><strong>再提出</strong> <img src="'+A+'" alt="再提出ステータス">: <strong>再提出</strong>ステータスは、コメントが追加されたことを示し、検証が完了するまで、アーティストがタスクの作業を継続し、新しいバージョンを公開することを促します。</p><p>これらの<strong>ステータス</strong>は、Kitsuで達成可能なことの例にすぎません。必要に応じて独自のステータスを作成することも可能です。</p><p>これを行うには、メインページから、[タスクステータスの追加]ボタン（../img/getting-started/add_task_status.png）をクリックします。</p><p>次に、ご自身の<strong>タスクステータス</strong>について、いくつかの詳細を定義する必要があります。</p><p>[ステータスの追加]ボタン（../img/getting-started/add_status.png）</p><ul><li><strong>NAME</strong>、マウスをステータスに重ねた際に表示されるステータスの明示的な名前。</li><li><strong>SHORT NAME</strong>、Kitsuに表示される名前。</li><li><strong>IS DEFAULT</strong>、Kitsuがすべてのタスクにデフォルトで表示する最初のステータス。Kitsuではデフォルトステータスは<strong>1つ</strong>のみ設定できます。</li><li><strong>完了</strong>、このステータスがタスクの検証に使用される場合（クォータ管理、ToDoリストの整理、エピソード統計の更新に役立ちます）。</li><li><strong>再提出の値</strong>、このステータスがタスクのコメントに使用される場合（タスクタイプページやエピソード統計ページでのやり取りを追跡するのに役立ちます）。</li><li><strong>IS ARTIST ALLOWED</strong>（アーティストが許可されているか）：アーティストがこのステータスを設定することは許可されていますか？ いいえの場合、アーティストは利用可能なステータスのリストでこのステータスを見ることはできません。 ただし、アーティストはこれにコメントを投稿することはできます。</li><li><strong>IS CLIENT ALLOWED</strong>（クライアントが許可されているか）：クライアントがこのステータスを使用することはできますか？ いいえの場合、クライアントは利用可能なステータスのリストでこのステータスを見ることはできません。</li><li><strong>フィードバックリクエスト</strong>：このステータスがレビュー依頼に使用された場合（タイムシートを使用しない場合のノルマ管理に役立ちます）、このステータスはToDoリストの「保留中」タブに表示され、これらのステータスはすべて<strong>マイチェック</strong>ページにグループ化されます。このステータスを使用するたびに、Kitsuは<strong>プレビューの公開</strong>を促します）。 最後に、このステータスに使用する背景の<strong>色</strong>を選択します。</li></ul><p><strong>確認</strong>をクリックして変更を保存します。</p><p>ステータス**がグローバルライブラリに作成され、制作で使用できるようになりました。</p><p>::: ヒント 制作のどの段階でも、ここに戻って必要に応じてさらに<strong>タスクステータス</strong>を作成し、 制作に追加することができます。 :::</p><p>::: 警告 「コンセプトステータス」のカテゴリの下に、いくつかのタスクステータスがリストされていることに気づくでしょう。これらはシステムによって使用されるもので、ここで変更することはできますが、新しいものを追加することはできません。 :::</p><h2 id="自動化" tabindex="-1">自動化 <a class="header-anchor" href="#自動化" aria-label="Permalink to “自動化”">​</a></h2><h3 id="新しいステータスの作成-自動化" tabindex="-1">新しいステータスの作成 自動化 <a class="header-anchor" href="#新しいステータスの作成-自動化" aria-label="Permalink to “新しいステータスの作成 自動化”">​</a></h3><p>ステータス自動化<strong>は、事前に定義された基準に基づいて、タスクのステータスを自動的に変更するルールまたは条件を定義します。</strong>ステータス自動化**は、アセットタスクとショットタスクの両方に対して設定できます。</p><p>アセットの場合、タスク間で<strong>ステータス自動化</strong>を設定できます。たとえば、コンセプトタスクのステータスが「完了」に設定されると、下流のモデリングタスクのステータスが自動的に「準備完了」に変更されます。</p><p>さらに、タスクのステータスに基づいて<strong>アセットステータス</strong>を更新する<strong>ステータス自動化</strong>を作成することもできます。たとえば、コンセプトタスクが「完了」に設定されると、リンクされたアセットステータスが「レイアウト」に設定されます。</p><p>::: ヒント Automationで、<strong>最新のプレビューをコピー</strong>するようにKitsuに依頼することもできます。 :::</p><p>メインメニューに移動します！<a href="../img/getting-started/main_button.png">メインメニュー</a><strong>Automation</strong>を選択します。</p><p><img src="'+R+'" alt="メインメニューステータスAutomation"></p><p>このページから、<strong>[+ステータス自動化を追加]</strong>ボタンをクリックして<strong>ステータス自動化</strong>を作成できます。</p><p><img src="'+T+'" alt="ステータス自動化の作成"></p><p><strong>ステータス自動化</strong>は、<strong>アセット</strong>または<strong>ショット</strong>のいずれかに対して作成できます。</p><p>次に、自動化をトリガーする<strong>タスクタイプ</strong>と<strong>ステータス</strong>を選択できます。</p><p>どの<strong>タスクタイプ</strong>がオートメーションに対応するかを指定し、変更する<strong>ステータス</strong>を選択することができます。</p><p><img src="'+I+'" alt="詳細ステータスオートメーションの作成"></p><p>Ready For<strong>ステータスで変更を開始するには、トリガーを「ステータス」から「</strong>Ready For**」に変更する必要があります。</p><p>適用タスクタイプ<strong>が</strong>ショットタスクタイプ**と表示されるようになります。</p><p><img src="'+C+'" alt="詳細 ステータス自動化の作成 準備完了"></p><p>ショットの<strong>ステータス自動化</strong>を作成するには、<strong>エンティティタイプ</strong>をショットに変更する必要があります。</p><p>新しい<strong>ステータス自動化</strong>が<strong>グローバルライブラリ</strong>に作成されました。</p><p>::: 警告 プロダクションを作成したら、ステータス自動化を<strong>プロダクションライブラリ</strong>に追加する必要があります。 :::</p><p>::: ヒント プロダクションの作成中にいつでもここに戻って、必要に応じてさらに<strong>ステータス自動化</strong>を作成し、プロダクションに追加することができます。 :::</p><h2 id="_3d背景" tabindex="-1">3D背景 <a class="header-anchor" href="#_3d背景" aria-label="Permalink to “3D背景”">​</a></h2><h3 id="hdrファイルのグローバルライブラリの作成" tabindex="-1">HDRファイルのグローバルライブラリの作成 <a class="header-anchor" href="#hdrファイルのグローバルライブラリの作成" aria-label="Permalink to “HDRファイルのグローバルライブラリの作成”">​</a></h3><p>3D Backgrounds 機能は、<code>.HDR</code> 背景を組み込むことで、3D ファイル（<code>.GLB</code>）のレビューが容易になり、3D ファイルのレビューが強化されます。</p><p><code>.GLB</code> ファイル形式は、さまざまな 3D アセットおよびリソースを包含するバイナリコンテナです。これらのアセットには、3D モデル、テクスチャ、マテリアル、およびアニメーションが含まれます。</p><p>警告 定義 これは、照明情報を使用して 3D ファイルをレビューできることを意味します。 :::</p><p>このセクションでは、独自の <code>.HDR</code> ファイルライブラリを作成して制作に使用することができます。</p><p>メインメニューに移動します！<a href="../img/getting-started/main_button.png">メインメニュー</a>から、<strong>3D背景</strong>を選択します。</p><p><img src="'+H+'" alt="メインメニューのプレビュー背景"></p><p>ここから、<strong>「新しい背景を追加」</strong>ボタンをクリックして <code>.HDR</code> 背景を追加できます。</p><p><img src="'+S+'" alt="プレビュー背景の追加"></p><p>このポイントから、<code>.HDR</code> 背景を選択し、名前を指定し、この <code>.HDR</code> をデフォルトの背景として使用するかどうかを決定する必要があります。</p><p>::: ヒント 「デフォルトとして使用」オプションにチェックを入れると、デフォルトのグレーの背景の代わりにこのHDRが制作全体に適用されます。 :::</p><p><img src="'+E+'" alt="メインメニューのプレビュー背景"></p><p>すべての <code>.HDR</code> ファイルをアップロードすると、Kitsu がそれらをリストとして表示します。</p><p><img src="'+L+'" alt="プレビュー背景が埋められた"></p><p>新しい <strong>3D 背景</strong> が <strong>グローバルライブラリ</strong> に作成されました。</p><p>::: 警告 制作を作成したら、<strong>制作ライブラリ</strong> に追加する必要があります。 :::</p><h2 id="設定" tabindex="-1">設定 <a class="header-anchor" href="#設定" aria-label="Permalink to “設定”">​</a></h2><h3 id="kitsu-の設定" tabindex="-1">Kitsu の設定 <a class="header-anchor" href="#kitsu-の設定" aria-label="Permalink to “Kitsu の設定”">​</a></h3><p>デフォルトの Kitsu ロゴをスタジオのロゴに置き換えるなど、スタジオに適用されるいくつかのグローバル設定を構成することができます。</p><p>これを行うには、メインメニューボタン <img src="'+t+'" alt="メインメニューボタン"> をクリックし、<strong>管理</strong>セクションで<strong>設定</strong>をクリックします。</p><p><img src="'+F+'" alt="メインメニューの設定"></p><h3 id="スタジオの設定" tabindex="-1">スタジオの設定 <a class="header-anchor" href="#スタジオの設定" aria-label="Permalink to “スタジオの設定”">​</a></h3><p><strong>スタジオロゴの設定</strong>をクリックし、使用する画像を選択します。これにより、サイトおよびアプリ内のさまざまな場所で表示されるKitsuロゴが置き換わります。また、Kitsuインスタンスで使用される<strong>スタジオ名</strong>を変更することもできます。</p><p>このページの残りの設定は、すべての制作に影響するグローバル設定です。これらの一部を以下に示します。</p><ul><li>1日あたり、チームが作業を行う時間を何時間にするか。</li><li>ダウンロード用のファイル名として、オリジナルのファイル名を使用するか。</li><li>デフォルトで画像をHD画質で表示する。このオプションは、インターネット接続が非常に高速な場合にのみ使用してください。</li><li>タイムシートについては、アーティストが1週間以上前のタイムシートを修正できないように制限することもできます。</li></ul><p><img src="'+$+'" alt="Kitsu Settings"></p><p>最後に、さまざまなチャット統合に関する設定も見つかります。設定方法の詳細については、<a href="./../chat-integration/">Chat Integration</a> セクションを参照してください。</p><p>::: 警告 作業が完了したら、最後に必ず<strong>設定を保存</strong>してください。 :::</p>',146)])])}const z=s(B,[["render",G]]);export{v as __pageData,z as default};
